            <div v-if="!isMobile" style="width:90%; padding: 20px;">
              <el-input placeholder="Search Photos" v-model="photosSearch" v-on:input="photosSearchInput">
                <i class="el-input__icon el-icon-search"></i>
              </el-input>
            </div>
            <div v-if="isMobile"
              :style="{ width: '90%', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: isMobile ? '5px' : '20px', paddingBottom: isMobile ? '10px' : '20px' }">
              <el-input style="width:49%;" placeholder="Search Photos" v-model="photosSearch"
                v-on:input="photosSearchInput">
                <i class="el-input__icon el-icon-search"></i>
