            <div
              style="height: auto; overflow-y: auto; max-height: calc(100vh - 416px); flex: 1 1 auto; display:flex; flex-direction: row; justify-content: space-evenly;  flex-wrap: wrap; width:100%;">
              <div style="padding-top:15px;" v-for="(file, j) in photos" :key="j">
                <el-image class="clipart-image" v-on:click="addClipart({ url: file.src.original, index: -1 }, $event)"
                  v-on:mousedown="$event.preventDefault()" style="width: 120px; height: auto" :src="file.src.tiny"
                  fit="fill"></el-image>
