            <div style="display:flex; justify-content:center; align-items:center; padding-top:15px; padding-bottom:15px;">
              <el-pagination small layout="prev, pager, next" :total="150" :page-size="15"
                :current-page="photosCurrentPage" v-on:current-change="photosPaginationEvent">
              </el-pagination>
            </div>
          </div>
