        <!-- canvas && toolbox -->
        <div style="flex: 1 1 0%; display: flex; flex-direction: column; position: relative;">
          <!-- canvas -->
          <div style="flex: 1 1 0%; display: flex; padding: 1px;">
            <div id="editor-container" style="flex: 1 1 0%; position: relative; overflow: hidden;">
              <div style="position: absolute; height: 100%; width: 100%;"> <canvas id="canvas"></canvas>
