<script>
import { ElButton, ElPagination,
  ElInput, ElImage, ElUpload} from 'element-plus'
  import 'element-plus/dist/index.css'
import fabric from '../canvas-modules/fabricModifications'
import clipartsJson from '../assets/temp-server-response/cliparts.json'
import fontsJson from '../assets/temp-server-response/fonts.json'
import { jsPDF } from 'jspdf'
import 'svg2pdf.js'
import * as THREE from 'three';
export default {
  name: 'EditorComponent',
  props: {
    //adminMode: Boolean
  },
  components: { ElButton, ElPagination, ElInput, ElImage, ElUpload},
  data() {
    return {
      hostUrl: 'https://honeybadger7846.github.io/dist', //'http://localhost:3000', //https://honeybadger7846.github.io/dist
      activeFontsCategory: ['Kids'],
      activeElementsCategory: 'flowers',
      isMobile: false,
      //canvas: null,
      activeSelection: null,
      zoom: 100,
      fonts: [],
      tab: null,
      loading: true,
      pages: [],
      activePage: null,
      fontsDialog: false,
      preview3dDialog: false,
      pageDialog: {
        open: false,
        pageIndex: null,
        action: 'Add',
        left: 0,
        top: 0,
        width: 595,
        height: 842,
        textColor: '#ffffff',
        name: 'SIDE 1',
        preview: null,
        colorIndex: 0,
        colors: [],
        svg: null
      },
      elements: [],
      visibleElements: [],
      elementsCurrentPage: 1,
      elementsTotalPages: 0,
      elementsSearch: '',
      photos: [],
      photosCurrentPage: 1,
      photosTotalPages: 0,
      photosSearch: 'People',
      templates: [],
      isSaving: false,
      adminMode: false
    }
  },
  methods: {
    toggleAdminMode: function() {
      this.adminMode = !this.adminMode
     if (!this.activePage && !this.adminMode) {
          this.setPage(0)
          this.tab = null
        }
        if (this.adminMode) {
          this.canvas.clear()
          this.tab = null
          this.activePage = null
        }
       // let backgroundContainer = document.getElementById('editor-container')
       //   backgroundContainer.style.backgroundImage = null
    },
    addPage: function (options) {
      this.canvas.addPage(options, (page) => {
        console.log(page)
        this.pages.push(page)
      //  if (!this.activePage) {
       //   this.setPage(0)
       // }
      })
    },
    removePage: function (index) {
      this.pages.splice(index, 1)
      //this.activePage = null
      //this.setPage(index - 1)
    },
    updatePageDialog: function(index) {
      if (this.pages[index]) {
       this.pageDialog = {...this.pageDialog, ...this.pages[index]}
      }
      this.pageDialog.pageIndex = index
      this.pageDialog.action = 'Save'
    },
    pageDialogAction: function() {
      if (this.pages[this.pageDialog.pageIndex] && this.pageDialog.action === 'Save') {
        this.pages[this.pageDialog.pageIndex].name = this.pageDialog.name
        this.pages[this.pageDialog.pageIndex].colors = this.pageDialog.colors
      //  if (this.pageDialog.preview) {
        //  this.pages[this.pageDialog.pageIndex].preview = this.pageDialog.preview
       // }
        if (this.pageDialog.pageIndex === this.activePage) this.setPage(this.pageDialog.pageIndex, false)
      }
      if (this.pageDialog.action === 'Add') {
        this.addPage(this.pageDialog)
      }
    },
    setPageFill: function (event) {
      if (event !== null) {
        this.pageDialog.fill = event
      }
    },
    setPage: function (index) {
      // save state of current page
     if (typeof this.activePage === 'number' && this.pages[this.activePage]) {
        this.pages[this.activePage].json = this.canvas.toJSON(['evented', 'role', 'selectable', 'originalSize'
       ])
      }
      let page = this.pages[index]
      if (!page) return
      this.canvas.clear()
      // ensure that width && height && fill match
      if (Array.isArray((page.json || {}).objects)) {
        console.log(page.json.objects)
        let foundPage = false
        page.json.objects.forEach(object => {
          if (object.role === 'page') {
            foundPage = true
            // handle rect case
            if (object.type === 'rect') {
              object.width = Number(page.width)
              object.height = Number(page.height)
              //object.fill = page.fill
            }
          }
        })
        console.log(foundPage)
        if (!foundPage) {
          this.canvas._createObjectPage(page, (pageObject) => {
            page.json.objects.unshift(pageObject)
            this.canvas.loadPage(JSON.stringify(page.json), () => {
              this.activePage = index
            })
          })
        } else {
          this.canvas.loadPage(JSON.stringify(page.json), () => {
            this.activePage = index
          })
        }
      }
    },
    setPageColor: function(pageIndex, index) {
      if (!this.pages[pageIndex]) return
    let color = this.pages[pageIndex].colors[index]
    this.pages[pageIndex].colorIndex = index
    if (pageIndex === this.activePage) {
      fabric.Image.fromURL(color.image, (img) => {
      if (this._backgroundImage) this.canvas.remove(this._backgroundImage)
    this.canvas.getObjects().forEach(object => {
            if (object.role === 'background-image') {
                this.canvas.remove(object)
            }
        })
                img.set({
                    left: -Number(color.left),
                    top: -Number(color.top),
                    role: 'background-image',
                    evented: false,
                    selectable: false
                })
                this.canvas.add(img)
               this.canvas.moveTo(img, 0)
               this._backgroundImage = img
              // let backgroundContainer = document.getElementById('editor-container')
         // backgroundContainer.style.backgroundImage = null
            }, { crossOrigin: 'Anonymous' })
    } else {
this.setPage(pageIndex)
    }
    console.log(color)
    },
    loadBase64Font(event) {
      this.canvas.loadFontBase64(event)
    },
    groupSelection: function () {
      if (!this.canvas.getActiveObject()) {
        return
      }
      if (this.canvas.getActiveObject().type === 'activeSelection') {
        this.canvas.getActiveObject().toGroup()
        this.canvas.fire('selection:updated', {
          target: this.canvas.getActiveObject()
        })
        this.canvas.requestRenderAll()
        return
      }
      if (this.canvas.getActiveObject().type === 'group') {
        this.canvas.getActiveObject().toActiveSelection()
        this.canvas.fire('selection:updated', {
          target: this.canvas.getActiveObject()
        })
        this.canvas.requestRenderAll()
        return
      }
    },
    cloneSelection: function () {
      if (!this.canvas.getActiveObject()) {
        return
      }
      this.canvas.getActiveObject().clone((cloned) => {
        cloned.clone((clonedObj) => {
          this.canvas.discardActiveObject()
          clonedObj.set({
            left: clonedObj.left + 50,
            top: clonedObj.top - 50,
            evented: true,
          })
          if (clonedObj.type === 'activeSelection') {
            clonedObj.canvas = this.canvas;
            clonedObj.forEachObject((obj) => {
              this.canvas.add(obj)
            });
            clonedObj.setCoords();
          } else {
            this.canvas.add(clonedObj)
          }
          cloned.top -= 50;
          cloned.left += 50;
          this.canvas.setActiveObject(clonedObj);
          this.canvas.requestRenderAll();
        });
      });
    },
    deleteSelection: function () {
      if (!this.canvas.getActiveObject()) {
        return
      }
      this.canvas.remove(...this.canvas.getActiveObjects())
      this.canvas.discardActiveObject()
      this.canvas.requestRenderAll()
    },
    undo: function () {
      this.canvas.undo()
    },
    redo: function () {
      this.canvas.redo()
    },
    zoomToFit: function () {
      this.canvas.centerPage()
    },
    zoomIn: function () {
      this.canvas.zoomIn()
    },
    zoomOut: function () {
      this.canvas.zoomOut()
    },
    sliderZoom: function (value) {
      if (this.canvas) {
        this.canvas.zoomTo(value / 100)
      }
    },
    exportDrawing() {
      this.isSaving = true
      if (typeof this.activePage === 'number' && this.pages[this.activePage]) {
        this.pages[this.activePage].json = this.canvas.toJSON(['evented', 'role', 'selectable', 'originalSize'
        ])
      }
      this.pages.forEach(page => {
        let exportCanvas = new fabric.Canvas()
        exportCanvas.loadPage(JSON.stringify(page.json), () => {
          exportCanvas.getObjects().forEach(object => {
            if (object.role === 'bleed-temp') {
              exportCanvas.remove(object)
            }
            if (object.role === 'bg') {
              exportCanvas._design = object
            }
          })
          let originalSize = exportCanvas._design ? exportCanvas._design.originalSize : { width: 3840, height: 3840 }
          let pngBounds = exportCanvas._page.getBoundingRect()
          let designBounds = exportCanvas._design.getBoundingRect()
          let multiplier = originalSize.width / pngBounds.width
          // bug fix, temp
          exportCanvas._design.scaleToWidth(designBounds.width + (pngBounds.width - designBounds.width))
          let svgString = exportCanvas.toSVG({
            viewBox: {
              x: exportCanvas._design.left,
              y: exportCanvas._design.top,
              width: exportCanvas._design.width * exportCanvas._design.scaleX,
              height: exportCanvas._design.height * exportCanvas._design.scaleY
            },
            width: pngBounds.width * multiplier,
            height: pngBounds.height * multiplier
          })
          let blob = new Blob([svgString], {
            type: "image/svg+xml;charset=utf-8",
          });
          let url = URL.createObjectURL(blob);
          let link = document.createElement("a");
          link.href = url;
          link.download = 'output.svg';
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          let orientation = exportCanvas._page.width * exportCanvas._page.scaleX >= exportCanvas._page.height * exportCanvas._page.scaleY ? 'l' : 'p'
          const parser = new DOMParser();
          const svgElement = parser.parseFromString(svgString, "image/svg+xml");
          const doc = new jsPDF(orientation, 'px', [designBounds.width * multiplier, designBounds.height * multiplier])
          doc.svg(svgElement.lastChild, {
            x: 0,
            y: 0,
            width: designBounds.width * multiplier,
            height: designBounds.height * multiplier
          }).then(() => {
            doc.save('output.pdf')
          })
          let pngImage = exportCanvas.toDataURL({
            left: pngBounds.left,
            top: pngBounds.top,
            width: pngBounds.width,
            height: pngBounds.height,
            multiplier: originalSize.width / pngBounds.width
          })
          let linkPng = document.createElement("a");
          linkPng.href = pngImage;
          linkPng.download = 'output.png';
          document.body.appendChild(linkPng);
          linkPng.click();
          document.body.removeChild(linkPng);
        })
      })
      setTimeout(() => { this.isSaving = false }, 3000)
    },
    getBase64(file) {
      return new Promise(function (resolve, reject) {
        let reader = new FileReader();
        let imgResult = "";
        reader.readAsDataURL(file);
        reader.onload = function () {
          imgResult = reader.result;
        };
        reader.onerror = function (error) {
          reject(error);
        };
        reader.onloadend = function () {
          resolve(imgResult);
        };
      });
    },
    addClipart: function (options, event) {
      this.canvas.addClipart(options.url, options.index)
      if (this.isMobile) {
        this.tab = ''
      }
      event.preventDefault()
    },
    addDesign: function (url, event) {
      this.canvas.addDesign(url)
      if (this.isMobile) {
        this.tab = ''
      }
      event.preventDefault()
    },
    addDesignBase64: function (file) {
      this.getBase64(file).then(res => {
        this.canvas.addDesign(res)
        if (this.isMobile) {
          this.tab = ''
        }
      })
    },
    uploadImageBase64: function (file) {
      this.getBase64(file).then(res => {
        this.canvas.addClipart(res, -1, (img) => {
          if (Math.min(img.width, img.height) < 1500) {
            this.$message({
              showClose: true,
              message: 'We strongly suggest a larger file for better results',
              type: 'warning',
              duration: 6000
            });
          }
        })
      })
    },
    uploadImageBase64ForBackground: function (file, page, setImage = true) {
      if (!file) return
      let reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        if (page) page.preview = reader.result
        if (setImage) this.setImageBackgroundPreview(reader.result)
      };
    },
    setImageBackgroundPreview: function (src) {
      /*
      if (this._backgroundImage) this.canvas.remove(this._backgroundImage)
    this.canvas.getObjects().forEach(object => {
            if (object.role === 'background-image') {
                this.canvas.remove(object)
            }
        })
        */
      let img = new Image()
        img.src = src
        img.onload = () => {
          let backgroundContainer = document.getElementById('editor-container')
          backgroundContainer.style.backgroundImage = `url("${img.src}")`
          backgroundContainer.style.backgroundRepeat = 'no-repeat'
          backgroundContainer.style.backgroundSize = 'contain'
          backgroundContainer.style.backgroundPosition = 'center'
          if (this.isMobile) {
            this.tab = ''
          }
        }
    },
    uploadSvgBase64: function (file) {
      this.getBase64(file).then(res => {
        this.canvas.addSvg(res)
      })
    },
    addCircle: function () {
      this.canvas.addCircle()
    },
    addTriangle: function () {
      this.canvas.addTriangle()
    },
    addRect: function () {
      this.canvas.addRect()
    },
    addEllipse: function () {
      this.canvas.addEllipse()
    },
    addText: function (options) {
      this.canvas.addText(options)
      if (this.isMobile) {
        this.tab = ''
      }
    },
    toggleTextEditing: function () {
      let activeObject = this.canvas.getActiveObject()
      if (!activeObject.isEditing) {
        activeObject.enterEditing()
        activeObject.setCursorPosition(activeObject.getTextLength())
      } else {
        activeObject.exitEditing()
      }
    },
    setLayer: function (layer) {
      this.canvas.positionActiveObject(layer)
      this.canvas.requestRenderAll()
    },
    setFilter: function (filter) {
      let activeObject = this.canvas.getActiveObject()
      if (!activeObject) return
      if (activeObject.type !== 'image') return
      activeObject.filters = []
      if (filter === 'greyscale') {
        activeObject.filters.push(new fabric.Image.filters.Grayscale());
      }
      if (filter === 'technicolor') {
        activeObject.filters.push(new fabric.Image.filters.Technicolor());
      }
      if (filter === 'kodachrome') {
        activeObject.filters.push(new fabric.Image.filters.Kodachrome());
      }
      if (filter === 'vintage') {
        activeObject.filters.push(new fabric.Image.filters.Vintage());
      }
      if (filter === 'red') {
        activeObject.filters.push(new fabric.Image.filters.BlendColor({
          color: 'red',
          mode: 'add',
          alpha: 0.4
        }));
      }
      if (filter === 'yellow') {
        activeObject.filters.push(new fabric.Image.filters.BlendColor({
          color: 'yellow',
          mode: 'add',
          alpha: 0.4
        }));
      }
      activeObject.applyFilters();
    },
    setAlign: function (align) {
      this.canvas.alignActiveObject(align)
      this.canvas.requestRenderAll()
    },
    setStyle: function (style) {
      if (!this.activeSelection) return
      for (const property in style) {
        if (style[property] === null) {
          delete style[property]
        }
      }
      if (style.textAlign) {
        const positions = ["left", "center", "right", "left"];
        const currentIndex = positions.findIndex((v) => v === style.textAlign);
        style.textAlign = positions[currentIndex + 1]
      }
      this.canvas.getActiveObject().set(style)
      if (this.canvas.getMissingFonts().length > 0 && style.fontFamily) {
        this.canvas.fire('missing:fonts', this.canvas.getMissingFonts())
      }
      this.canvas.fire('object:modified', {
        target: this.canvas.getActiveObject()
      })
      this.canvas.requestRenderAll()
    },
    navMenu: function (tab) {
      this.tab = this.tab === tab ? null : tab
      this.fontsDialog = false
      if (this.canvas) {
        this.canvas.discardActiveObject()
        this.canvas.requestRenderAll()
      }
    },
    elementsPaginationEvent: function (page) {
      this.elementsCurrentPage = page
    },
    elementsSearchInput: function (event) {
      this.elementsCurrentPage = 1
      this.visibleElements = this.elements.filter(element => element.category.includes(event))
    },
    photosPaginationEvent: function (page) {
      fetch(`https://api.pexels.com/v1/search?page=${page}&per_page=15&query=${this.photosSearch}`, {
        headers: {
          Authorization: "563492ad6f91700001000001d6fdba6f7d1b4e85a6234198ca28e0a6"
        }
      }).then((response) => {
        return response.json()
      }).then((result) => {
        this.photos = result.photos
        this.photosCurrentPage = result.page
      })
    },
    photosSearchInput: function (event) {
      fetch(`https://api.pexels.com/v1/search?query=${event}`, {
        headers: {
          Authorization: "563492ad6f91700001000001d6fdba6f7d1b4e85a6234198ca28e0a6"
        }
      }).then((response) => {
        return response.json()
      }).then((result) => {
        this.photos = result.photos
        this.photosCurrentPage = result.page
      })
    },
    checkPhotos() {
      if (this.tab === 'photos' && this.photos.length === 0) {
        fetch(`https://api.pexels.com/v1/search?query=people`, {
          headers: {
            Authorization: "563492ad6f91700001000001d6fdba6f7d1b4e85a6234198ca28e0a6"
          }
        }).then((response) => {
          return response.json()
        }).then((result) => {
          this.photos = result.photos
          this.photosCurrentPage = result.page
        })
      }
    }
  },
  mounted() {
    if (THREE) {
      // 3d support working
    }
    const resizeEditorObserver = new ResizeObserver((entries) => {
      entries.forEach(entry => {
        let width = entry.contentRect.width
        this.isMobile = width < 580 ? true : false
        let vh = window.innerHeight * 0.01;
        // Then we set the value in the --vh custom property to the root of the document
        document.documentElement.style.setProperty('--vh', `${vh}px`);
      });
    });
    resizeEditorObserver.observe(document.getElementById('editor'));
    // for filters
    if (fabric.isWebglSupported()) {
      fabric.filterBackend = new fabric.WebglFilterBackend();
      fabric.textureSize = fabric.maxTextureSize;
    }
    this.loading = false
    this.canvas = new fabric.Canvas('canvas', {
      fireMiddleClick: true,
      skipOffscreen: true,
      preserveObjectStacking: true
    })
    this.canvas.loadDefaultFont()
    setInterval(() => {
      this.canvas.renderCanvas(this.canvas.contextContainer, this.canvas._objects)
    }, 250)
    this.canvas.initKeyEvents()
    this.canvas.on('object:modified', (selection) => {
      console.log(selection)
      this.activeSelection = typeof selection.target.getUIStyles ==
        'function' ? selection
          .target.getUIStyles() : selection.target
    })
    this.canvas.on('selection:created', (selection) => {
      console.log(selection)
      this.activeSelection = typeof selection.target.getUIStyles ==
        'function' ? selection
          .target.getUIStyles() : selection.target
    })
    this.canvas.on('selection:updated', (selection) => {
      this.activeSelection = typeof selection.target.getUIStyles ==
        'function' ? selection
          .target.getUIStyles() : selection.target
    })
    this.canvas.on('text:selection:changed', (selection) => {
      this.activeSelection = typeof selection.target.getUIStyles ==
        'function' ? selection
          .target.getUIStyles() : selection.target
    })
    this.canvas.on('selection:cleared', () => {
      this.activeSelection = null
    })
    this.canvas.on('zoom:changed', () => {
      this.zoom = Number((this.canvas.getZoom() * 100).toFixed(0))
    })
    this.canvas.on('missing:fonts', (fonts) => {
      let availableFonts = []
      this.fonts.forEach(family => {
        availableFonts.push(...family.fonts)
      })
      fonts.forEach(mFont => {
        let fontMatch = availableFonts.filter(font => font.name === mFont)[0]
        if (fontMatch) {
          let url = fontMatch.url
          fetch(`${this.hostUrl}/${url}`).then((response) => {
            return response.arrayBuffer()
          }).then((buffer) => {
            this.canvas.loadFont(buffer, mFont)
          })
        }
      })
    })
    // canvas resize 
    const resizeObserver = new ResizeObserver((entries) => {
      entries.forEach(entry => {
        let width = entry.contentRect.width
        let height = entry.contentRect.height
        this.canvas.setWidth(width)
        this.canvas.setHeight(height)
        this.canvas.centerPage()
      });
    });
    resizeObserver.observe(document.getElementById('editor-container'));
    /*
    this.addPage({
      width: 595,
      height: 842,
      fill: '#fff',
      name: ''
    })
    */
    // predefined values for testing, data should come from server
    if (clipartsJson) {
      this.elements = clipartsJson
    }
    if (fontsJson) {
      this.fonts = fontsJson
    }
  }
}
</script>
